package main

const MAX_BITS = 18

type DSU struct {
    parent []int
    rank   []int
}

func NewDSU(n int) *DSU {
    parent := make([]int, n)
    rank := make([]int, n)
    for i := range parent {
        parent[i] = i
        rank[i] = 0
    }
    return &DSU{parent, rank}
}

func (d *DSU) Find(x int) int {
    if d.parent[x] != x {
        d.parent[x] = d.Find(d.parent[x])
    }
    return d.parent[x]
}

func (d *DSU) Union(x, y int) {
    xr := d.Find(x)
    yr := d.Find(y)
    if xr == yr {
        return
    }
    if d.rank[xr] < d.rank[yr] {
        d.parent[xr] = yr
    } else if d.rank[xr] > d.rank[yr] {
        d.parent[yr] = xr
    } else {
        d.parent[yr] = xr
        d.rank[xr]++
    }
}

func Solve(nums []int64) int64 {
    n := int64(len(nums))
    arr := make([]int, n)
    for i := int64(0); i < n; i++ {
        arr[i] = int(nums[i])
    }

    fullMask := (1 << MAX_BITS) - 1
    for k := fullMask; k >= 0; k-- {
        dsu := NewDSU(int(n))

        anchor := make([]int, 1<<MAX_BITS)
        for i := range anchor {
            anchor[i] = -1
        }

        valid := true
        for i := 0; i < int(n); i++ {
            if (i & k) != k {
                continue
            }
            extra := i & fullMask &^ k
            if anchor[extra] == -1 {
                anchor[extra] = i
            } else {
                dsu.Union(i, anchor[extra])
            }
            comp := fullMask &^ extra
            s := comp
            for {
                if anchor[s] != -1 {
                    dsu.Union(i, anchor[s])
                }
                if s == 0 {
                    break
                }
                s = (s - 1) & comp
            }
        }

        for i := 0; i < int(n); i++ {
            a := arr[i]
            target := i
            if dsu.Find(a) != dsu.Find(target) {
                valid = false
                break
            }
        }

        if valid {
            return int64(k)
        }
    }
    return 0
}
