func solve(nums []int64) int64 {
    n := len(nums)
    sorted := true
    for i := range nums {
        if int64(i) != nums[i] {
            sorted = false
            break
        }
    }
    if sorted {
        return 0
    }

    parent := make([]int, n + (1 << 17))
    for i := range parent {
        parent[i] = i
    }

    var find func(int) int
    find = func(x int) int {
        if parent[x] != x {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    union := func(a, b int) {
        a = find(a)
        b = find(b)
        if a != b {
            parent[b] = a
        }
    }

    check := func(k int64) bool {
        for i := range parent {
            parent[i] = i
        }

        totalNodes := n
        fullMask := (1 << 17) - 1
        comp := fullMask &^ int(k)

        exists := make([]bool, 1 << 17)
        for a := 0; a < n; a++ {
            if int64(a) & k == k {
                mask := int64(a) &^ k
                exists[mask] = true
            }
        }

        for m := 0; m < (1 << 17); m++ {
            if !exists[m] {
                continue
            }
            union(totalNodes + m, n + m)
            for j := 0; j < 17; j++ {
                if (m >> j) & 1 == 1 {
                    nm := m ^ (1 << j)
                    if exists[nm] {
                        union(totalNodes + m, totalNodes + nm)
                    }
                }
            }
        }

        for a := int64(0); a < int64(n); a++ {
            if a & k == k {
                mask := a &^ k
                union(int(a), totalNodes + int(mask))
            }
        }

        pos := make([]int, n)
        for i, v := range nums {
            pos[v] = i
        }

        compOfA := make([]int, n)
        for i := 0; i < n; i++ {
            compOfA[i] = find(i)
        }
        for i := 0; i < n; i++ {
            if find(i) == find(pos[i]) {
                continue
            }
            return false
        }
        return true
    }

    k := int64(1 << 17 - 1)
    for {
        if k < 0 {
            return 0
        }
        if check(k) {
            return k
        }
        k--
    }
}
