import "math/bits"

func solve(nums []int64) int64 {
    n := len(nums)
    if n == 1 {
        return 0
    }

    maxVal := n - 1
    bitLen := bits.Len(uint(maxVal))
    full_mask := (1 << bitLen) - 1

    var ans int64 = 0

    for bit := bitLen - 1; bit >= 0; bit-- {
        candidate := ans | (1 << bit)
        valid := true

        for i := 0; i < n; i++ {
            if int64(i) == nums[i] {
                continue
            }
            a := i
            b := int(nums[i])
            if (a & int(candidate)) != int(candidate) {
                valid = false
                break
            }
            if (b & int(candidate)) != int(candidate) {
                valid = false
                break
            }
        }
        if !valid {
            continue
        }

        U := full_mask &^ int(candidate)
        m := bits.OnesCount(uint(U))
        bitList := make([]int, 0, m)
        for j := 0; j < bitLen; j++ {
            bitVal := 1 << j
            if U & bitVal != 0 {
                bitList = append(bitList, j)
            }
        }

        total_m := 1 << m
        exists := make([]bool, total_m)
        for a := 0; a < n; a++ {
            if a > full_mask {
                continue
            }
            if (a & int(candidate)) != int(candidate) {
                continue
            }
            aExt := a & U
            packed := 0
            for idx, b := range bitList {
                if (aExt >> b) & 1 != 0 {
                    packed |= (1 << idx)
                }
            }
            if packed < total_m {
                exists[packed] = true
            }
        }

        compID := make([]int, total_m)
        for i := range compID {
            compID[i] = -1
        }
        currentComp := 0
        for x := 0; x < total_m; x++ {
            if !exists[x] || compID[x] != -1 {
                continue
            }
            currentComp++
            compID[x] = currentComp
            queue := []int{x}
            for len(queue) > 0 {
                u := queue[0]
                queue = queue[1:]
                compMask := (total_m - 1) ^ u
                submask := compMask
                for {
                    if exists[submask] && compID[submask] == -1 {
                        compID[submask] = currentComp
                        queue = append(queue, submask)
                    }
                    if submask == 0 {
                        break
                    }
                    submask = (submask - 1) & compMask
                }
            }
        }

        for i := 0; i < n; i++ {
            if int64(i) == nums[i] {
                continue
            }
            iInt := i
            num := int(nums[i])
            iExt := iInt & U
            iMask := 0
            for idx, b := range bitList {
                if (iExt >> b) & 1 != 0 {
                    iMask |= (1 << idx)
                }
            }

            nExt := num & U
            nMask := 0
            for idx, b := range bitList {
                if (nExt >> b) & 1 != 0 {
                    nMask |= (1 << idx)
                }
            }

            if iMask >= total_m || nMask >= total_m {
                valid = false
                break
            }
            if compID[iMask] == -1 || compID[nMask] == -1 || compID[iMask] != compID[nMask] {
                valid = false
                break
            }
        }

        if valid {
            ans = int64(candidate)
        }
    }
    return ans
}
